class Node(object):
 def __init__(self, data):
  self.data = data
  self.left = None
  self.right = None

class BinaryTree(object):
 def __init__(self):
  self.root = None

 def insert(self, data):
  if self.root == None:
   self.root = Node(data)
  else:
   self._insert(data, self.root)

 def _insert(self, data, node):
  if data < node.data:
   if node.left == None:
    node.left = Node(data)
   else:
    self._insert(data, node.left)
  else:
   if node.right == None:
    node.right = Node(data)
   else:
    self._insert(data, node.right)

