class BinarySearchTree:
    def __init__(self):
        self.root = None

    def add(self, val):
        new_node = Node(val)
        if not self.root:
            self.root = new_node
        else:
            curr = self.root
            while True:
                if val < curr.val:
                    if not curr.left:
                        curr.left = new_node
                        break
                    curr = curr.left
                else:
                    if not curr.right:
                        curr.right = new_node
                        break
                    curr = curr.right
        return self.root

