# Steps to implement Bubble Sort Algorithm: 
# 1. Loop through the list with two indices, the current element and the NEXT element 
# 2. Compare current element with the NEXT element 
# 3. If current element is greater than NEXT element, swap them 
# 4. Repeat this till the list is sorted 

def bubble_sort(list): 
    # Traverse through all elements of list 
    for i in range(0, len(list)-1): 
        for j in range(0, len(list)-i-1): 
            if list[j] > list[j+1]: 
                list[j], list[j+1] = list[j+1], list[j]

