def quick_sort(A):
  # Base case
  if len(A) <= 1:
    return A

  # Choose pivot
  pivot_idx = len(A) // 2
  pivot_val = A[pivot_idx]

  # Initialize left and right lists
  left = []
  right = []

  # Populate left and right lists
  for i in range(len(A)):
    if i == pivot_idx:
      continue
    elif A[i] < pivot_val:
      left.append(A[i])
    else:
      right.append(A[i])

  # Return sorted left and right lists
  return quick_sort(left) + [pivot_val] + quick_sort(right)

