class Fraction:

    def __init__(self, numerator, denominator):
        self.numerator = numerator
        self.denominator = denominator

    def __add__(self, obj2):
        n = self.numerator * obj2.denominator + obj2.numerator * self.denominator
        d = self.denominator * obj2.denominator
        return Fraction(n, d)

    def __sub__(self, obj2):
        n = self.numerator * obj2.denominator - obj2.numerator * self.denominator
        d = self.denominator * obj2.denominator
        return Fraction(n, d)

    def __mul__(self, obj2):
        n = self.numerator * obj2.numerator
        d = self.denominator * obj2.denominator
        return Fraction(n, d)

    def __truediv__(self, obj2):
        n = self.numerator * obj2.denominator
        d = self.denominator * obj2.numerator
        return Fraction(n, d)

    def simplify_fraction(self):
        i = 2
        while i <= self.numerator:
            if self.numerator % i == 0 and self.denominator % i == 0:
                self.numerator = self.numerator / i
                self.denominator = self.denominator / i
            else:
                i += 1

