import ast

class StaticAnalysis:
    def detect_errors(self, code):
        tree = ast.parse(code)
        errors = []
        for node in ast.walk(tree):
            if isinstance(node, ast.FunctionDef):
                errors.extend(self.check_function_def(node))
            elif isinstance(node, ast.Call):
                errors.extend(self.check_function_call(node))
        return errors

    def check_function_def(self, function):
        errors = []
        if not function.args.args:
            errors.append(('No parameters passed to function', function.lineno))
        return errors

    def check_function_call(self, call):
        errors = []
        if not call.args:
            errors.append(('No arguments passed to function call', call.lineno))
        return errors

