def quickSort(list, key):
 if len(list) <= 1:
  return list

 pivot = len(list) // 2
 pivotVal = list[pivot][key]

 less = [x for x in list if x[key] < pivotVal]
 equal = [x for x in list if x[key] == pivotVal]
 more = [x for x in list if x[key] > pivotVal]

 return quickSort(less, key) + equal + quickSort(more, key)

