class Vector2D:
    def __init__(self, x = 0, y = 0):
        self.x = x
        self.y = y

    # Adds two vectors
    def __add__(self, other):
        x = self.x + other.x
        y = self.y + other.y
        return Vector2D(x, y)

    # Subtracts two vectors
    def __sub__(self, other):
        x = self.x - other.x
        y = self.y - other.y
        return Vector2D(x, y)

    # Multiplies a vector by a scalar
    def __mul__(self, other):
        x = self.x * other
        y = self.y * other
        return Vector2D(x, y)  

    # Divides a vector by a scalar
    def __truediv__(self, other):
        x = self.x / other
        y = self.y / other
        return Vector2D(x, y)

