def minCoins(coins, n, amount):
    result= [0 for i in range(amount + 1)] 

    # Initializing all the result values to sys.maxint 
    for i in range(1,amount + 1): 
        result[i] = float("Inf") 

    # Storing the minimum coin array value for a given amount
    for i in range(1,amount + 1): 
        for coin in coins: 
            if coin <=i: 
                sub_res = result[i - coin] 
                if sub_res != float("Inf") and sub_res + 1 < result[i]: 
                    result[i] = sub_res + 1

