class BinomialTree:
    def __init__(self, n):
        self.n = n

    def create(self):
        tree = [None] * self.n
        tree[0] = 1

        for i in range(self.n):
            for j in range(i+1):
                if tree[i] is not None:
                    if j == 0:
                        tree[i + 1] = tree[i] * 2
                    else:
                        tree[i + 1] += tree[i - j]
        return tree

