def lcs(s1, s2):
    dp = [[0 for i in range(len(s2)+1)]for i in range(len(s1)+1)]

    res = ""
    maxLength = 0

    for i in range(len(s1)+1):
        for j in range(len(s2)+1):
            if i == 0 or j == 0:
                dp[i][j] = 0
            elif s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
                if dp[i][j] > maxLength:
                    res = s1[i-dp[i][j]:i]
                    maxLength = len(res)
            else:
                dp[i][j] = 0

