def classify_email(email):
    email_words = re.findall("[a-zA-Z0-9]+", email)
    frequency = nltk.FreqDist(email_words)
    common_words = frequency.most_common(30)

    spam_words = ["buy", "free", "unlimited", "cash", "click", "amazing"]
    is_spam = False

    for word in common_words:
        if word in spam_words:
            is_spam = True

    if is_spam:
        print("This email is classified as SPAM.")
    else:
        print("This email is classified as NOT SPAM.")

