def most_frequent_letter(string):
    frequency = {}
    for letter in string:
        if letter.isalpha() and letter != ' ':
            if letter in frequency:
                frequency[letter] += 1
            else:
                frequency[letter] = 1
    highest_frequency = 0
    most_used_letter = ''
    for letter, freq in frequency.items():
        if freq > highest_frequency:
            highest_frequency = freq
            most_used_letter = letter
    return (most_used_letter, highest_frequency)

