class LinkedList:
    def __init__(self):
        self.head = None


    def push(self, data):
        # Allocate the Node & Put in the data 
        new_node = Node(data)

        # Make next of new Node as head 
        new_node.next = self.head

        # Move the head to point to new Node 
        self.head = new_node 

    # Utility function to print the linked LinkedList 
    def printList(self): 
        temp = self.head 
        while(temp): 
            print(temp.data, end=" ") 
            temp = temp.next

