def longest_common_subsequence(s1, s2):
    m = len(s1)
    n = len(s2)
    dp = [[0 for i in range(n+1)] for i in range(m+1)]

    for i in range(m):
        for j in range(n):
            if s1[i] == s2[j]:
                dp[i+1][j+1] = dp[i][j] + 1
            else:
                dp[i+1][j+1] = max(dp[i+1][j], dp[i][j+1])

    return dp[m][n]

