from nltk import sent_tokenize

def summarize(text, limit=5):
    # Splitting the text into sentences
    sentences = sent_tokenize(text)

    # Generating word frequency table
    word_frequencies = {}
    for sentence in sentences:
        words = sentence.split()
        for word in words:
            if word not in word_frequencies.keys():
                word_frequencies[word] = 1
            else:
                word_frequencies[word] += 1

    # Generating word scores
    word_scores = {}
    for word in word_frequencies.keys():
        score = 1 / word_frequencies[word]
        word_scores[word] = score

    # Generating sentence scores
    sentence_scores = {}
    for sentence in sentences:
        sentence_wordcount = len(sentence.split())
        sentence_wordscore = 0
        for word in sentence.split():
            if word in word_scores.keys():
                sentence_wordscore += word_scores[word]
        sentence_score = sentence_wordscore / sentence_wordcount
        sentence_scores[sentence] = sentence_score

    # Generating summary
    summary = ''
    sorted_sentences = sorted(sentence_scores.items(),
                              key=lambda x: x[1],
                              reverse=True)
    for s in sorted_sentences[:limit]:
        summary += f'{s[0]}\n'

    return summary

