    def getScore(self, player):
        score = 0
        for card in self.deck:
            if card[1] in ['J', 'Q', 'K']:
                score += 10
            elif card[1] == 'A':
                score += 11
            else:
                score += int(card[1])
        self.scores[player] = score
        return score

    # Check if a player won or there is a tie
    def isWinner(self, player1, player2):
        score1 = self.getScore(player1)
        score2 = self.getScore(player2)

