def knapsack(wt, val, n, W):
    if n == 0 or W == 0:
        return 0 
    elif wt[n - 1] > W: 
        return knapsack(wt, val, n - 1, W) 
    else: 
        return max(val[n - 1] + knapsack(wt, val, n - 1, W - wt[n - 1]), knapsack(wt, val, n - 1, W)) 

