def generate_parentheses(n):
    """
    Generates all possible valid parentheses combinations with n pairs of parentheses.
    """
    res = []
    def backtrack(s = '', left = 0, right = 0):
        if len(s) == 2 * n:
            res.append(s)
            return
        if left < n:
            backtrack(s + '(', left+1, right)
        if right < left:
            backtrack(s + ')', left, right+1)

    backtrack()
    return res

