    if len(letters) == 0:
        return []

    if len(letters) == 1:
        return [letters]

    permuted_letters = []

    for letter in letters:
        remaining_letters = [letter2 for letter2 in letters if letter2 != letter]
        permutations = permute_letters(remaining_letters)

        for permutation in permutations:
            permuted_letters.append([letter] + permutation)

