    if len(str1) > len(str2):
        longer, shorter = str1, str2
    else:
        longer, shorter = str2, str1

    # Check if strings are the same for all possible shifts
    for i in range(len(longer)-len(shorter)+1):
        if longer[i:len(shorter)+i] == shorter:
            return True

    return False

