def compute_similarity(s1, s2):
    len1 = len(s1)
    len2 = len(s2)
    max_len = max(len1, len2)
    count = 0

    for i in range(max_len):
        if i >= len1 or i >= len2:
            break
        if s1[i] == s2[i]:
            count += 1

    return count / max_len

