def optimize_matrix(matrix, target_sum):
    row_sums = [0] * len(matrix)
    col_sums = [0] * len(matrix[0])

    # Calculate the sum of each row and column
    for row in range(len(matrix)):
        for col in range(len(matrix[0])):
            row_sums[row] += matrix[row][col]
            col_sums[col] += matrix[row][col]

    # Check if the matrix can be optimized
    if min(row_sums) + min(col_sums) > target_sum or max(row_sums) + max(col_sums) < target_sum:
        return "Can't optimize"
    else:
        # Bring the matrix closer to the target sum by subtracting or 
        # adding an amount from each row and column
        for row in range(len(matrix)):
            for col in range(len(matrix[0])):
                matrix[row][col] += (target_sum - (row_sums[row] + col_sums[col])) // 2
